  (0,'Разработка и актуализация методологии ПОД/ФТ/ФРОМУ','Разработка, актуализация и методологическое сопровождение внутренних документов и правил внутреннего контроля в целях ПОД/ФТ/ФРОМУ.','Единая актуальная методология','regulatory','4.1','актуализация методологии под разработка фрому','high'),
  (1,'Организация процессов финансового мониторинга','Организация, регламентация и методическое обеспечение процессов финансового мониторинга в подразделениях банка.','Стандартизация процессов','operational','4.1','мониторинг организация процессов финансового','high'),
  (2,'Консультирование работников по вопросам ПОД/ФТ','Консультирование и методическая помощь работникам банка по вопросам применения правил внутреннего контроля в целях ПОД/ФТ.','Повышение качества исполнения','communication','4.1','вопросам консультирование под работников','medium'),
  (3,'Выявление операций обязательного контроля','Выявление операций, подлежащих обязательному контролю, в соответствии с требованиями законодательства.','Полнота выявления','control','4.2','выявление контроль обязательного операций','high'),
  (4,'Формирование и направление отчётности в уполномоченный орган','Формирование и направление сведений и отчётности по операциям в уполномоченный орган в установленные сроки.','Своевременная отчётность','operational','4.2','направление орган отчетности уполномоченный формирование','high'),
  (5,'Методическая поддержка по обязательному контролю','Методическая поддержка подразделений по вопросам обязательного контроля и формирования отчётности.','Корректность применения правил','communication','4.2','контроль методическая обязательному поддержка','medium'),
  (6,'Мониторинг подозрительных операций','Мониторинг и выявление операций, имеющих признаки подозрительных, в режиме, близком к реальному времени.','Своевременное выявление','control','4.3','мониторинг операций подозрительных','high'),
  (7,'Формирование сообщений о подозрительных операциях','Подготовка и формирование сообщений о подозрительных операциях по результатам мониторинга.','Корректная фиксация','operational','4.3','операциях подозрительных сообщений формирование','high'),
  (8,'Мониторинг операций электронной коммерции','Мониторинг операций в сфере электронной коммерции на предмет признаков подозрительной деятельности.','Контроль рисков e-commerce','control','4.3.3','коммерции мониторинг операций электронной','high'),
  (9,'Оценка деятельности клиентов','Оценка деятельности клиентов на предмет рисков ПОД/ФТ, включая оценку операций и поведения клиента.','Оценка клиентских рисков','analytical','4.4','клиентов оценка','high'),
  (10,'Углублённые проверки деятельности клиентов','Проведение углублённых проверок деятельности клиентов при выявлении повышенного риска.','Снижение риска','control','4.4.1','клиентов проверки углубленные','high'),
  (11,'Оценка потенциальных клиентов','Оценка потенциальных клиентов на этапе принятия на обслуживание (KYC/EDD).','Отсев высокорисковых на входе','analytical','4.4.3','клиентов оценка потенциальных','high'),
  (12,'Аналитическая поддержка подразделений департамента','Аналитическая поддержка подразделений департамента, подготовка аналитических материалов и справок.','Аналитическое обеспечение','analytical','4.5','аналитическая департамента поддержка подразделений','high'),
  (13,'Оценка рисков государственного оборонного заказа','Оценка рисков по операциям в рамках государственного оборонного заказа (ГОЗ).','Контроль рисков ГОЗ','control','4.6','государственного заказа оборонного оценка рисков','high'),
  (14,'Взаимодействие с контрольно-надзорными органами','Организация взаимодействия с контрольно-надзорными органами по вопросам финансового мониторинга (фрагмент без чёткого кода раздела).','','communication','','взаимодействие контроль надзорными органами','medium')
)
INSERT INTO t_p61016064_digital_innovation_i.dept_functions
    (project_id, dept_name, title, description, goals, category, priority, normalized_title, source_section_code)
SELECT 1, 'Департамент финансового мониторинга (ДФМ)', s.title, s.descr, s.goals, s.category, s.idx, s.norm, s.section
FROM seed s
WHERE NOT EXISTS (
    SELECT 1 FROM t_p61016064_digital_innovation_i.dept_functions f
    WHERE f.project_id = 1 AND f.normalized_title = s.norm AND f.source_section_code = s.section
);